import React, { useState, useEffect } from 'react';
import { useTables } from '../hooks/useTables';
import { updateTableStatus, toggleTableRequest, resetTable } from '../firebase/tableActions';
import { 
  Bell, Utensils, Moon, RefreshCw, FileText, CreditCard, 
  RotateCcw, Clock, LayoutGrid, List, Users,
  Maximize2, Minimize2 
} from 'lucide-react';

const TimeSinceInteraction = ({ timestamp }) => {
  const [timeStr, setTimeStr] = useState("0m");
  useEffect(() => {
    if (!timestamp) return;
    const calc = () => {
      const date = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
      const diffMins = Math.floor((new Date() - date) / 60000);
      setTimeStr(diffMins < 60 ? `${diffMins}m` : `${Math.floor(diffMins/60)}h ${diffMins%60}m`);
    };
    calc();
    const inv = setInterval(calc, 60000);
    return () => clearInterval(inv);
  }, [timestamp]);
  return <span className="text-[10px] font-black text-gray-500 flex items-center gap-1 uppercase"><Clock size={10}/> {timeStr}</span>;
};

const ToggleButton = ({ active, icon, onClick, color, bgActive }) => (
  <button 
    onClick={(e) => { e.stopPropagation(); onClick(); }}
    className={`p-3 rounded-xl flex justify-center items-center transition-all border ${
      active 
      ? `${bgActive} ${color} border-mictlan-gold shadow-[0_0_10px_rgba(212,175,55,0.3)]` 
      : 'bg-black/40 text-gray-600 border-gray-800 hover:border-gray-600'
    }`}
  >
    {icon}
  </button>
);

export default function TableGrid({ isCollapsed, setIsCollapsed }) {
  const { tables, loading } = useTables();
  const [viewMode, setViewMode] = useState('linear');

  if (loading) return <div className="p-10 text-center text-mictlan-gold animate-pulse uppercase tracking-widest font-bold">Chargement de la salle...</div>;

  const getStatusStyle = (table) => {
    if (table.requests?.needWaiter || table.status === 'alert') return 'bg-mictlan-red/10 border-mictlan-red shadow-[0_0_15px_rgba(220,38,38,0.2)] animate-pulse';
    if (table.requests?.dontDisturb) return 'bg-purple-900/20 border-purple-500';
    if (table.requests?.readyToOrder) return 'bg-green-900/20 border-green-500';
    if (table.requests?.needBill || table.requests?.needTPE) return 'bg-blue-900/20 border-blue-500';
    if (table.status === 'occupied') return 'bg-mictlan-gold/5 border-mictlan-gold/30';
    return 'bg-mictlan-dark-gray/30 border-gray-800';
  };

  const handleLinearClick = (table) => {
    const statusCycle = ['idle', 'occupied', 'alert', 'idle'];
    const currentIdx = statusCycle.indexOf(table.status) !== -1 ? statusCycle.indexOf(table.status) : 0;
    const nextStatus = statusCycle[(currentIdx + 1) % statusCycle.length];
    
    if (nextStatus === 'idle') resetTable(table.fireId);
    else updateTableStatus(table.fireId, nextStatus);
  };

  return (
    <div className="flex flex-col gap-8 w-full max-w-7xl mx-auto pb-20 px-4 text-gray-300">
      
      {/* HEADER SALLE */}
      <div className="flex justify-between items-center border-b border-gray-800 pb-4">
        <h2 className="text-xl font-bold text-mictlan-gold flex items-center uppercase tracking-[0.3em]">
          <Users className="mr-3 w-6 h-6" /> État des Tables
        </h2>
        <div className="flex gap-3">
          <button 
            onClick={() => setIsCollapsed(!isCollapsed)}
            className="flex items-center gap-2 px-4 py-2 bg-gray-900 text-gray-400 rounded-full border border-gray-800 hover:border-mictlan-gold transition-all text-[10px] font-black uppercase tracking-widest"
          >
            {isCollapsed ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
            {isCollapsed ? 'Expand All' : 'Collapse All'}
          </button>
          <button 
            onClick={() => setViewMode(prev => prev === 'linear' ? 'toggles' : 'linear')}
            className="px-4 py-2 bg-gray-800 text-mictlan-gold rounded-full border border-gray-700 text-[10px] font-black uppercase tracking-widest"
          >
            {viewMode === 'linear' ? 'Mode Cycle' : 'Mode Toggles'}
          </button>
        </div>
      </div>

      {/* GRILLE DES TABLES */}
      <div className={`grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 transition-all duration-500 ease-in-out overflow-hidden ${isCollapsed ? 'max-h-0 opacity-0' : 'max-h-[3000px] opacity-100'}`}>
        {tables.map(table => (
          <div key={table.fireId} className={`relative p-5 rounded-3xl border-2 transition-all duration-300 ${getStatusStyle(table)}`}>
            <div className="flex justify-between items-start mb-4">
              <span className="text-2xl font-black text-mictlan-gold tracking-tighter">T-{table.name || table.id}</span>
              {table.lastUpdated && <TimeSinceInteraction timestamp={table.lastUpdated} />}
            </div>
            {viewMode === 'linear' ? (
              <div className="h-32 flex flex-col items-center justify-center cursor-pointer group" onClick={() => handleLinearClick(table)}>
                <span className="text-sm font-black uppercase tracking-[0.2em] text-gray-300 group-hover:text-mictlan-gold transition-colors">
                  {table.status === 'idle' ? 'Libre' : table.status}
                </span>
                <div className="flex gap-2 mt-3">
                    {table.requests?.needWaiter && <Bell size={14} className="text-mictlan-red animate-bounce" />}
                    {table.requests?.needBill && <FileText size={14} className="text-blue-400" />}
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-3 gap-2">
                <ToggleButton active={table.requests?.needWaiter} icon={<Bell size={16}/>} color="text-white" bgActive="bg-mictlan-red" onClick={() => toggleTableRequest(table.fireId, 'needWaiter', table.requests?.needWaiter)} />
                <ToggleButton active={table.requests?.readyToOrder} icon={<Utensils size={16}/>} color="text-white" bgActive="bg-green-600" onClick={() => toggleTableRequest(table.fireId, 'readyToOrder', table.requests?.readyToOrder)} />
                <ToggleButton active={table.requests?.dontDisturb} icon={<Moon size={16}/>} color="text-white" bgActive="bg-purple-600" onClick={() => toggleTableRequest(table.fireId, 'dontDisturb', table.requests?.dontDisturb)} />
                <ToggleButton active={table.requests?.nextPlate} icon={<RefreshCw size={16}/>} color="text-white" bgActive="bg-orange-500" onClick={() => toggleTableRequest(table.fireId, 'nextPlate', table.requests?.nextPlate)} />
                <ToggleButton active={table.requests?.needBill} icon={<FileText size={16}/>} color="text-white" bgActive="bg-blue-600" onClick={() => toggleTableRequest(table.fireId, 'needBill', table.requests?.needBill)} />
                <ToggleButton active={table.requests?.needTPE} icon={<CreditCard size={16}/>} color="text-white" bgActive="bg-teal-600" onClick={() => toggleTableRequest(table.fireId, 'needTPE', table.requests?.needTPE)} />
              </div>
            )}
            <button 
              onClick={(e) => { e.stopPropagation(); resetTable(table.fireId); }}
              className="absolute -top-2 -right-2 p-2 bg-gray-900 border border-gray-700 text-gray-500 hover:text-mictlan-red rounded-full shadow-xl transition-colors"
            >
              <RotateCcw size={12} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Package, Maximize2, Minimize2, ChevronDown, ChevronUp, AlertTriangle, CheckCircle, XCircle } from 'lucide-react';
import { useInventory } from '../hooks/useInventory';
import { useLogs } from '../hooks/useLogs';

export default function Inventory({ isCollapsed, setIsCollapsed, user }) {
  const [isOpen, setIsOpen] = useState(true);
  const { inventory, updateStatus } = useInventory();
  const { addLog } = useLogs();

  useEffect(() => {
    setIsOpen(!isCollapsed);
  }, [isCollapsed]);

  const getStatusColor = (status) => {
    switch (status) {
      case 'ok': return 'text-green-500';
      case 'low': return 'text-orange-500';
      case 'out': return 'text-red-600 animate-pulse';
      default: return 'text-gray-500';
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'ok': return <CheckCircle size={16} className="text-green-500" />;
      case 'low': return <AlertTriangle size={16} className="text-orange-500" />;
      case 'out': return <XCircle size={16} className="text-red-600" />;
      default: return <Package size={16} className="text-gray-500" />;
    }
  };

  const handleStatusClick = async (item) => {
    const statusCycle = { ok: 'low', low: 'out', out: 'ok' };
    const nextStatus = statusCycle[item.status] || 'ok';
    await updateStatus(item.id, nextStatus, item.name, addLog, user);
  };

  return (
    <div className="bg-mictlan-dark-gray/30 rounded-3xl border border-gray-800 overflow-hidden transition-all duration-300 shadow-lg">
      <div
        className="flex justify-between items-center p-6 cursor-pointer hover:bg-white/5 transition-colors"
        onClick={() => setIsOpen(!isOpen)}
      >
        <h2 className="text-sm font-black text-mictlan-gold uppercase tracking-[0.3em] flex items-center">
          <Package className="mr-2 w-4 h-4" /> Inventaire
        </h2>

        <div className="flex items-center gap-3">
          <button
            onClick={(e) => {
              e.stopPropagation();
              setIsCollapsed(!isCollapsed);
            }}
            className="p-1.5 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all"
            title={isCollapsed ? "Expand All" : "Collapse All"}
          >
            {isCollapsed ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>

          <div className="text-gray-500">
            {isOpen ? <ChevronUp size={18} /> : <ChevronDown size={18} className="text-mictlan-gold" />}
          </div>
        </div>
      </div>

      {isOpen && (
        <div className="px-6 pb-6">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
            {inventory.map((item) => (
              <div
                key={item.id}
                onClick={() => handleStatusClick(item)}
                className="bg-black/30 p-3 rounded-lg border border-gray-800 hover:border-mictlan-gold/50 cursor-pointer transition-all group"
              >
                <div className="flex items-center justify-between mb-2">
                  <span className="text-xs font-medium text-gray-300 uppercase tracking-wide">
                    {item.name}
                  </span>
                  {getStatusIcon(item.status)}
                </div>
                <div className={`text-xs font-bold ${getStatusColor(item.status)}`}>
                  {item.status === 'ok' ? 'EN STOCK' :
                   item.status === 'low' ? 'STOCK FAIBLE' :
                   item.status === 'out' ? 'ÉPUISÉ' : 'INCONNU'}
                </div>
                {item.quantity && (
                  <div className="text-[10px] text-gray-500 mt-1">
                    Qté: {item.quantity}
                  </div>
                )}
              </div>
            ))}
          </div>

          {inventory.length === 0 && (
            <div className="text-center py-8 text-gray-500">
              <Package size={48} className="mx-auto mb-4 opacity-50" />
              <p className="text-sm">Aucun article en inventaire</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useInventory } from '../hooks/useInventory';
import { ShoppingCart, Maximize2, Minimize2, ChevronDown, ChevronUp } from 'lucide-react';

export default function ShoppingList({ isCollapsed, setIsCollapsed }) {
  const { inventory, loading } = useInventory();
  const [isOpen, setIsOpen] = useState(true);

  useEffect(() => { setIsOpen(!isCollapsed); }, [isCollapsed]);

  const lowStockItems = (inventory || []).filter(item => 
    item.status === 'low' || item.status === 'out'
  );

  return (
    <div className="bg-mictlan-dark-gray/30 rounded-3xl border border-gray-800 overflow-hidden transition-all duration-300">
      <div className="flex justify-between items-center p-6 cursor-pointer hover:bg-white/5" onClick={() => setIsOpen(!isOpen)}>
        <h2 className="text-sm font-black text-mictlan-gold uppercase tracking-[0.3em] flex items-center">
          <ShoppingCart className="mr-2 w-4 h-4" /> Liste de Courses
        </h2>
        <div className="flex items-center gap-3">
          <button 
            onClick={(e) => { e.stopPropagation(); setIsCollapsed(!isCollapsed); }}
            className="p-1.5 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all"
          >
            {isCollapsed ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>
          {isOpen ? <ChevronUp size={16} className="text-gray-500"/> : <ChevronDown size={16} className="text-mictlan-gold"/>}
        </div>
      </div>
      <div className={`transition-all duration-500 overflow-hidden ${isOpen ? 'max-h-[1000px] opacity-100 p-6 pt-0' : 'max-h-0 opacity-0'}`}>
        {loading ? (
          <p className="text-xs text-gray-500 uppercase font-bold tracking-widest">Chargement...</p>
        ) : lowStockItems.length > 0 ? (
          <div className="space-y-2">
            {lowStockItems.map(item => (
              <div key={item.id} className="flex justify-between items-center p-3 bg-black/20 rounded-xl border border-gray-800/50">
                <span className="text-xs font-bold text-gray-300 uppercase">{item.name}</span>
                <span className={`text-[10px] font-black uppercase px-2 py-1 rounded-md ${item.status === 'out' ? 'bg-mictlan-red/20 text-mictlan-red' : 'bg-orange-500/20 text-orange-500'}`}>
                  {item.status}
                </span>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-xs text-gray-600 italic uppercase font-bold">Tout est en stock.</p>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useLogs } from '../hooks/useLogs';
import { ScrollText, ChevronDown, ChevronUp, Maximize2, Minimize2, Clock } from 'lucide-react';

const ActivityLog = ({ isCollapsed, setIsCollapsed }) => {
  const { logs, loading } = useLogs();
  const [isOpen, setIsOpen] = useState(true);

  // Synchronisation avec le bouton global
  useEffect(() => {
    setIsOpen(!isCollapsed);
  }, [isCollapsed]);

  return (
    <div className="bg-mictlan-dark-gray/30 rounded-3xl border border-gray-800 overflow-hidden transition-all duration-300 shadow-lg">
      {/* Header cliquable */}
      <div 
        className="flex justify-between items-center p-6 cursor-pointer hover:bg-white/5 transition-colors"
        onClick={() => setIsOpen(!isOpen)}
      >
        <h2 className="text-sm font-black text-mictlan-gold uppercase tracking-[0.3em] flex items-center">
          <ScrollText className="mr-2 w-4 h-4" /> Historique d'Activité
        </h2>
        
        <div className="flex items-center gap-3">
          {/* Bouton Global */}
          <button 
            onClick={(e) => { 
              e.stopPropagation(); 
              setIsCollapsed(!isCollapsed); 
            }}
            className="p-1.5 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all"
          >
            {isCollapsed ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>
          
          {/* Indicateur individuel */}
          <div className="text-gray-500">
            {isOpen ? <ChevronUp size={18} /> : <ChevronDown size={18} className="text-mictlan-gold" />}
          </div>
        </div>
      </div>

      {/* Zone de contenu rétractable */}
      <div 
        className={`transition-all duration-500 ease-in-out overflow-hidden ${
          isOpen ? 'max-h-[500px] opacity-100 p-6 pt-0' : 'max-h-0 opacity-0'
        }`}
      >
        <div className="bg-black/20 rounded-2xl border border-gray-800/50 overflow-hidden">
          <div className="max-h-64 overflow-y-auto custom-scrollbar p-4 space-y-3">
            {loading ? (
              <p className="text-xs text-gray-500 uppercase font-bold text-center py-4">Chargement des logs...</p>
            ) : logs && logs.length > 0 ? (
              logs.map((log) => (
                <div key={log.id} className="flex flex-col gap-1 pb-3 border-b border-gray-800/50 last:border-0 last:pb-0">
                  <div className="flex justify-between items-start">
                    <span className="text-[11px] font-bold text-gray-300 uppercase leading-tight">
                      {log.message}
                    </span>
                    <span className="text-[9px] font-black text-mictlan-gold flex items-center gap-1 whitespace-nowrap ml-2">
                      <Clock size={10} /> {log.timestamp?.toDate().toLocaleDateString()} {log.timestamp?.toDate().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                    </span>
                  </div>
                  {log.user && (
                    <span className="text-[8px] font-bold text-gray-600 uppercase">
                      Par: {log.user}
                    </span>
                  )}
                </div>
              ))
            ) : (
              <p className="text-xs text-gray-600 italic text-center py-4">Aucune activité enregistrée.</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ActivityLog;

