import React, { useState, useEffect } from 'react';
import { db } from '../firebase/config';
import { doc, getDoc, setDoc, collection, getDocs, query, orderBy, serverTimestamp } from 'firebase/firestore';
import { Save, History, FileText, ChevronDown, ChevronUp, Maximize2, Minimize2 } from 'lucide-react';

export default function RequirementsCard({ isCollapsed, setIsCollapsed }) {
  const [content, setContent] = useState('');
  const [history, setHistory] = useState([]);
  const [isOpen, setIsOpen] = useState(true);

  useEffect(() => { setIsOpen(!isCollapsed); }, [isCollapsed]);

  useEffect(() => {
    const load = async () => {
      const docRef = doc(db, 'requirements', 'current');
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) setContent(docSnap.data().text);
      const q = query(collection(db, 'requirements_versions'), orderBy('date', 'desc'));
      const snap = await getDocs(q);
      setHistory(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    };
    load();
  }, []);

  return (
    <div className="bg-mictlan-dark-gray/30 rounded-3xl border border-gray-800 overflow-hidden transition-all duration-300">
      <div className="flex justify-between items-center p-6 cursor-pointer hover:bg-white/5" onClick={() => setIsOpen(!isOpen)}>
        <h2 className="text-sm font-black text-mictlan-gold uppercase tracking-[0.3em] flex items-center">
          <FileText className="mr-2 w-4 h-4" /> Cahier des Charges
        </h2>
        <div className="flex items-center gap-3">
          <button 
            onClick={(e) => { e.stopPropagation(); setIsCollapsed(!isCollapsed); }}
            className="p-1.5 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all"
          >
            {isCollapsed ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>
          {isOpen ? <ChevronUp size={16} className="text-gray-500"/> : <ChevronDown size={16} className="text-mictlan-gold"/>}
        </div>
      </div>
      <div className={`transition-all duration-500 overflow-hidden ${isOpen ? 'max-h-[1000px] opacity-100 p-6 pt-0' : 'max-h-0 opacity-0'}`}>
        <textarea 
          className="w-full h-48 p-4 bg-black/20 border border-gray-800 rounded-2xl font-mono text-xs text-gray-300 focus:ring-1 focus:ring-mictlan-gold/30 outline-none resize-none mb-4"
          value={content}
          onChange={(e) => setContent(e.target.value)}
        />
        <button onClick={() => alert('Sauvegardé')} className="w-full bg-gray-800 hover:bg-mictlan-gold hover:text-black text-mictlan-gold font-bold py-2 rounded-lg text-xs uppercase tracking-widest">
          <Save size={14} className="inline mr-2" /> Sauvegarder
        </button>
      </div>
    </div>
  );
}

