              <p className="text-[10px] font-black text-gray-500 uppercase mb-1">{ind.name}</p>
              <p className={`text-xs font-bold uppercase ${ind.color}`}>{ind.status}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

