import React, { useState, useEffect } from 'react';
import { Activity, Maximize2, Minimize2, ChevronDown, ChevronUp } from 'lucide-react';

// On ajoute isCollapsed et setIsCollapsed dans les arguments de la fonction
export default function StatusDashboard({ isCollapsed, setIsCollapsed }) {
  const [isOpen, setIsOpen] = useState(true);

  // Cette partie est CRUCIALE : elle écoute le bouton "Collapse All" global
  useEffect(() => {
    setIsOpen(!isCollapsed);
  }, [isCollapsed]);

  const indicators = [
    { name: "Alerte 1", status: "OK", color: "text-green-500" },
    { name: "Alerte 2", status: "OK", color: "text-green-500" },
    { name: "Alerte 3", status: "Low", color: "text-orange-500" }
  ];

  return (
    <div className="bg-mictlan-dark-gray/30 rounded-3xl border border-gray-800 overflow-hidden transition-all duration-300 shadow-lg">
      {/* Header cliquable pour ouvrir/fermer cette carte précisément */}
      <div 
        className="flex justify-between items-center p-6 cursor-pointer hover:bg-white/5 transition-colors"
        onClick={() => setIsOpen(!isOpen)}
      >
        <h2 className="text-sm font-black text-mictlan-gold uppercase tracking-[0.3em] flex items-center">
          <Activity className="mr-2 w-4 h-4" /> Alertes
        </h2>

        <div className="flex items-center gap-3">
          {/* Le bouton "Collapse All" présent sur la carte */}
          <button 
            onClick={(e) => { 
              e.stopPropagation(); // Empêche de fermer la carte locale par erreur
              setIsCollapsed(!isCollapsed); 
            }}
            className="p-1.5 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all"
            title={isCollapsed ? "Expand All" : "Collapse All"}
          >
            {isCollapsed ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>

          {/* Indicateur visuel local */}
          <div className="text-gray-500">
            {isOpen ? <ChevronUp size={18} /> : <ChevronDown size={18} className="text-mictlan-gold" />}
          </div>
        </div>
      </div>

      {/* Contenu qui se masque/s'affiche avec animation */}
      <div 
        className={`transition-all duration-500 ease-in-out overflow-hidden ${
          isOpen ? 'max-h-[500px] opacity-100 p-6 pt-0' : 'max-h-0 opacity-0'
        }`}
      >
        <div className="grid grid-cols-3 gap-4">
          {indicators.map((ind, i) => (
            <div key={i} className="p-4 bg-black/20 rounded-2xl border border-gray-800 text-center group hover:border-mictlan-gold/30 transition-all">
