import { useState, useEffect } from 'react';
import { useInventory } from '../hooks/useInventory';
import { ShoppingCart, Maximize2, Minimize2, ChevronDown, ChevronUp } from 'lucide-react';

export default function ShoppingList() {
  const { inventory, loading } = useInventory();
  const [isOpen, setIsOpen] = useState(true);

  const lowStockItems = (inventory || []).filter(item => 
    item.status === 'low' || item.status === 'out'
  );

  return (
    <div className="bg-mictlan-dark-gray/30 rounded-3xl border border-gray-800 overflow-hidden transition-all duration-300">
      <div className="flex justify-between items-center p-6 cursor-pointer hover:bg-white/5" onClick={() => setIsOpen(!isOpen)}>
        <h2 className="text-sm font-black text-mictlan-gold uppercase tracking-[0.3em] flex items-center">
          <ShoppingCart className="mr-2 w-4 h-4" /> Liste de Courses
        </h2>
        <div className="flex items-center gap-3">
          <button 
            onClick={(e) => { e.stopPropagation(); setIsOpen(!isOpen); }}
            className="p-1.5 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all"
          >
            {!isOpen ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>
          {isOpen ? <ChevronUp size={16} className="text-gray-500"/> : <ChevronDown size={16} className="text-mictlan-gold"/>}
        </div>
      </div>
      <div className={`transition-all duration-500 overflow-hidden ${isOpen ? 'max-h-[1000px] opacity-100 p-6 pt-0' : 'max-h-0 opacity-0'}`}>
        {loading ? (
          <p className="text-xs text-gray-500 uppercase font-bold tracking-widest">Chargement...</p>
        ) : lowStockItems.length > 0 ? (
          <div className="space-y-2">
            {lowStockItems.map(item => (
              <div key={item.id} className="flex justify-between items-center p-3 bg-black/20 rounded-xl border border-gray-800/50">
                <span className="text-xs font-bold text-gray-300 uppercase">{item.name}</span>
                <span className={`text-[10px] font-black uppercase px-2 py-1 rounded-md ${item.status === 'out' ? 'bg-mictlan-red/20 text-mictlan-red' : 'bg-orange-500/20 text-orange-500'}`}>
                  {item.status}
                </span>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-xs text-gray-600 italic uppercase font-bold">Tout est en stock.</p>
        )}
      </div>
    </div>
  );
}

