  const [isOpen, setIsOpen] = useState(true);

  const lowStockItems = (inventory || []).filter(item => 
    item.status === 'low' || item.status === 'out'
  );

  return (
    <div className="bg-mictlan-dark-gray/30 rounded-3xl border border-gray-800 overflow-hidden transition-all duration-300">
