            onClick={(e) => { e.stopPropagation(); setIsOpen(!isOpen); }}
            className="p-1.5 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all"
          >
            {!isOpen ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>
          {isOpen ? <ChevronUp size={16} className="text-gray-500"/> : <ChevronDown size={16} className="text-mictlan-gold"/>}
